pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

/**
 * @title GlowToken
 * @dev Production ERC20 with mint/burn/pause and ownership controls
 */
contract GlowToken is ERC20, Ownable, Pausable {
    uint256 public constant MAX_SUPPLY = 1_000_000_000 * 10**18;

    event TokensMinted(address indexed to, uint256 amount);
    event TokensBurned(address indexed from, uint256 amount);

    constructor(
        string memory name,
        string memory symbol,
        address initialOwner
    ) ERC20(name, symbol) Ownable(initialOwner) {}

    function mint(address to, uint256 amount) external onlyOwner whenNotPaused {
        require(totalSupply() + amount <= MAX_SUPPLY, "Exceeds max supply");
        _mint(to, amount);
        emit TokensMinted(to, amount);
    }

    function burn(uint256 amount) external {
        _burn(msg.sender, amount);
        emit TokensBurned(msg.sender, amount);
    }

    function pause() external onlyOwner { _pause(); }
    function unpause() external onlyOwner { _unpause(); }

    function _update(address from, address to, uint256 value) internal override whenNotPaused {
        super._update(from, to, value);
    }
}

import { useState, useEffect, useCallback } from 'react';

interface WalletState {
  address: string | null;
  chainId: number | null;
  isConnected: boolean;
  isConnecting: boolean;
  error: string | null;
}

interface UseWallet extends WalletState {
  connect: () => Promise<void>;
  disconnect: () => void;
  switchChain: (chainId: number) => Promise<void>;
}

export function useWallet(): UseWallet {
  const [state, setState] = useState<WalletState>({
    address: null, chainId: null, isConnected: false, isConnecting: false, error: null,
  });

  const provider = typeof window !== 'undefined' ? window.ethereum : null;

  // Silent reconnect on mount
  useEffect(() => {
    if (!provider) return;
    provider.request({ method: 'eth_accounts' }).then((accs: unknown) => {
      const accounts = accs as string[];
      if (accounts.length) {
        setState(s => ({ ...s, address: accounts[0], isConnected: true }));
        provider.request({ method: 'eth_chainId' }).then((cid: unknown) => {
          setState(s => ({ ...s, chainId: parseInt(cid as string, 16) }));
        });
      }
    }).catch(() => {});

    const onAccounts = (accs: unknown) => {
      const a = accs as string[];
      setState(s => a.length ? { ...s, address: a[0], isConnected: true } : { ...s, address: null, isConnected: false });
    };
    const onChain = (cid: unknown) => setState(s => ({ ...s, chainId: parseInt(cid as string, 16) }));
    provider.on('accountsChanged', onAccounts);
    provider.on('chainChanged', onChain);
    return () => { provider.removeListener('accountsChanged', onAccounts); provider.removeListener('chainChanged', onChain); };
  }, []);

  const connect = useCallback(async () => {
    if (!provider) { setState(s => ({ ...s, error: 'No wallet detected. Install MetaMask.' })); return; }
    setState(s => ({ ...s, isConnecting: true, error: null }));
    try {
      const accs = await provider.request({ method: 'eth_requestAccounts' }) as string[];
      const cid = await provider.request({ method: 'eth_chainId' }) as string;
      setState(s => ({ ...s, address: accs[0], chainId: parseInt(cid, 16), isConnected: true, isConnecting: false }));
    } catch (err: unknown) {
      const msg = (err as { code?: number }).code === 4001 ? 'User rejected connection.' : 'Connection failed.';
      setState(s => ({ ...s, error: msg, isConnecting: false }));
    }
  }, [provider]);

  const disconnect = useCallback(() => {
    setState({ address: null, chainId: null, isConnected: false, isConnecting: false, error: null });
  }, []);

  const switchChain = useCallback(async (chainId: number) => {
    if (!provider) return;
    const hex = `0x${chainId.toString(16)}`;
    try {
      await provider.request({ method: 'wallet_switchEthereumChain', params: [{ chainId: hex }] });
    } catch (err: unknown) {
      if ((err as { code?: number }).code === 4902) throw new Error('Chain not added to wallet');
      throw err;
    }
  }, [provider]);

  return { ...state, connect, disconnect, switchChain };
}

// app/api/ai/chat/route.ts
import { NextRequest, NextResponse } from 'next/server';

export const runtime = 'edge';
export const maxDuration = 60;

export async function POST(req: NextRequest) {
  try {
    const { messages, model, temperature = 0.7, maxTokens = 4096 } = await req.json();

    if (!messages?.length) {
      return NextResponse.json({ error: 'Messages required' }, { status: 400 });
    }

    const apiKey = process.env.OPENROUTER_API_KEY;
    if (!apiKey) return NextResponse.json({ error: 'API key not configured' }, { status: 503 });

    const response = await fetch('https://openrouter.ai/api/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${apiKey}`,
        'HTTP-Referer': process.env.NEXT_PUBLIC_APP_URL ?? 'https://glowide.app',
        'X-Title': 'GlowIDE',
      },
      body: JSON.stringify({
        model: model ?? 'anthropic/claude-3.5-sonnet',
        messages: [
          { role: 'system', content: 'You are a senior full-stack Web3 engineer. Write production-ready code.' },
          ...messages,
        ],
        temperature,
        max_tokens: maxTokens,
        stream: true,
      }),
    });

    if (!response.ok) {
      const err = await response.json().catch(() => ({}));
      return NextResponse.json({ error: err.error?.message ?? 'AI service error' }, { status: response.status });
    }

    // Stream passthrough
    return new Response(response.body, {
      headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache', Connection: 'keep-alive' },
    });
  } catch (err) {
    return NextResponse.json({ error: String(err) }, { status: 500 });
  }
}

'use client';
import { useState, useEffect } from 'react';
import Link from 'next/link';
import { Menu, X } from 'lucide-react';

const LINKS = [
  { href: '/', label: 'Home' },
  { href: '/features', label: 'Features' },
  { href: '/docs', label: 'Docs' },
  { href: '/pricing', label: 'Pricing' },
];

export function Navbar() {
  const [open, setOpen] = useState(false);

  // Close on route change / resize
  useEffect(() => {
    const close = () => setOpen(false);
    window.addEventListener('resize', close);
    return () => window.removeEventListener('resize', close);
  }, []);

  return (
    <header className="sticky top-0 z-50 bg-gray-950/90 backdrop-blur-md border-b border-gray-800">
      <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
        {/* Logo */}
        <Link href="/" className="font-bold text-xl text-white">
          MyApp
        </Link>

        {/* Desktop nav */}
        <nav className="hidden md:flex items-center gap-6">
          {LINKS.map(l => (
            <Link key={l.href} href={l.href}
              className="text-sm text-gray-400 hover:text-white transition-colors">
              {l.label}
            </Link>
          ))}
          <Link href="/signup"
            className="px-4 py-2 bg-purple-600 hover:bg-purple-700 text-white text-sm rounded-lg transition-colors">
            Get Started
          </Link>
        </nav>

        {/* Mobile toggle */}
        <button onClick={() => setOpen(!open)} className="md:hidden p-2 text-gray-400 hover:text-white">
          {open ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
        </button>
      </div>

      {/* Mobile menu */}
      {open && (
        <div className="md:hidden border-t border-gray-800 bg-gray-950 px-4 py-4 space-y-2">
          {LINKS.map(l => (
            <Link key={l.href} href={l.href} onClick={() => setOpen(false)}
              className="block py-2.5 text-gray-300 hover:text-white text-sm transition-colors">
              {l.label}
            </Link>
          ))}
          <Link href="/signup" onClick={() => setOpen(false)}
            className="block w-full text-center px-4 py-2.5 bg-purple-600 hover:bg-purple-700 text-white text-sm rounded-lg transition-colors mt-2">
            Get Started
          </Link>
        </div>
      )}
    </header>
  );
}

