pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title StakingPool
 * @notice Stake LP tokens, earn reward tokens at a configurable rate
 */
contract StakingPool is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable stakingToken;
    IERC20 public immutable rewardToken;

    uint256 public rewardRate;           // rewards per second (1e18 scale)
    uint256 public lastUpdateTime;
    uint256 public rewardPerTokenStored;
    uint256 public totalStaked;
    uint256 public constant LOCK_PERIOD = 7 days;

    struct UserInfo {
        uint256 balance;
        uint256 rewardPerTokenPaid;
        uint256 pendingRewards;
        uint256 lastStakeTime;
    }
    mapping(address => UserInfo) public users;

    event Staked(address indexed user, uint256 amount);
    event Withdrawn(address indexed user, uint256 amount);
    event RewardClaimed(address indexed user, uint256 reward);
    event RewardRateUpdated(uint256 newRate);

    constructor(address _staking, address _reward, uint256 _rate, address _owner)
        Ownable(_owner)
    {
        stakingToken = IERC20(_staking);
        rewardToken = IERC20(_reward);
        rewardRate = _rate;
        lastUpdateTime = block.timestamp;
    }

    // ── View ──────────────────────────────────────────────────────────
    function rewardPerToken() public view returns (uint256) {
        if (totalStaked == 0) return rewardPerTokenStored;
        return rewardPerTokenStored + (
            (block.timestamp - lastUpdateTime) * rewardRate * 1e18 / totalStaked
        );
    }

    function earned(address account) public view returns (uint256) {
        UserInfo memory u = users[account];
        return u.balance * (rewardPerToken() - u.rewardPerTokenPaid) / 1e18 + u.pendingRewards;
    }

    // ── Modifiers ─────────────────────────────────────────────────────
    modifier updateReward(address account) {
        rewardPerTokenStored = rewardPerToken();
        lastUpdateTime = block.timestamp;
        if (account != address(0)) {
            users[account].pendingRewards = earned(account);
            users[account].rewardPerTokenPaid = rewardPerTokenStored;
        }
        _;
    }

    // ── Actions ───────────────────────────────────────────────────────
    function stake(uint256 amount) external nonReentrant updateReward(msg.sender) {
        require(amount > 0, "Amount must be > 0");
        stakingToken.safeTransferFrom(msg.sender, address(this), amount);
        users[msg.sender].balance += amount;
        users[msg.sender].lastStakeTime = block.timestamp;
        totalStaked += amount;
        emit Staked(msg.sender, amount);
    }

    function withdraw(uint256 amount) external nonReentrant updateReward(msg.sender) {
        UserInfo storage u = users[msg.sender];
        require(amount > 0 && amount <= u.balance, "Invalid amount");
        require(block.timestamp >= u.lastStakeTime + LOCK_PERIOD, "Tokens locked");
        u.balance -= amount;
        totalStaked -= amount;
        stakingToken.safeTransfer(msg.sender, amount);
        emit Withdrawn(msg.sender, amount);
    }

    function claimReward() external nonReentrant updateReward(msg.sender) {
        uint256 reward = users[msg.sender].pendingRewards;
        require(reward > 0, "No rewards");
        users[msg.sender].pendingRewards = 0;
        rewardToken.safeTransfer(msg.sender, reward);
        emit RewardClaimed(msg.sender, reward);
    }

    function setRewardRate(uint256 newRate) external onlyOwner updateReward(address(0)) {
        rewardRate = newRate;
        emit RewardRateUpdated(newRate);
    }
}

import express, { Request, Response, NextFunction } from 'express';
import { createClient } from '@supabase/supabase-js';

const app = express();
app.use(express.json());

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
);

// ── Auth middleware ───────────────────────────────────────────────────
async function auth(req: Request, res: Response, next: NextFunction) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'No token' });
  const { data: { user }, error } = await supabase.auth.getUser(token);
  if (error || !user) return res.status(401).json({ error: 'Invalid token' });
  (req as Request & { user: typeof user }).user = user;
  next();
}

// ── Projects CRUD ─────────────────────────────────────────────────────
app.get('/api/projects', auth, async (req, res) => {
  const user = (req as Request & { user: { id: string } }).user;
  const { data, error } = await supabase
    .from('projects')
    .select('*')
    .eq('user_id', user.id)
    .order('updated_at', { ascending: false });
  if (error) return res.status(500).json({ error: error.message });
  res.json({ projects: data });
});

app.post('/api/projects', auth, async (req, res) => {
  const user = (req as Request & { user: { id: string } }).user;
  const { name, description, language = 'typescript' } = req.body;
  if (!name) return res.status(400).json({ error: 'Name required' });
  const { data, error } = await supabase
    .from('projects')
    .insert({ name, description, language, user_id: user.id })
    .select()
    .single();
  if (error) return res.status(500).json({ error: error.message });
  res.status(201).json({ project: data });
});

app.put('/api/projects/:id', auth, async (req, res) => {
  const user = (req as Request & { user: { id: string } }).user;
  const { id } = req.params;
  const { name, description } = req.body;
  const { data, error } = await supabase
    .from('projects')
    .update({ name, description, updated_at: new Date().toISOString() })
    .eq('id', id)
    .eq('user_id', user.id)
    .select()
    .single();
  if (error) return res.status(500).json({ error: error.message });
  if (!data) return res.status(404).json({ error: 'Not found or unauthorized' });
  res.json({ project: data });
});

app.delete('/api/projects/:id', auth, async (req, res) => {
  const user = (req as Request & { user: { id: string } }).user;
  const { error } = await supabase.from('projects').delete().eq('id', req.params.id).eq('user_id', user.id);
  if (error) return res.status(500).json({ error: error.message });
  res.json({ success: true });
});

app.listen(3001, () => console.log('API running on port 3001'));

# Gas Optimization in Solidity — Key Techniques

## 1. Storage vs Memory vs Calldata
```solidity
// Expensive: reading storage in a loop
function badLoop() external {
    for (uint i = 0; i < arr.length; i++) { // arr.length reads storage every iteration
        // ...
    }
}

// Optimized: cache in memory
function goodLoop() external {
    uint len = arr.length; // single SLOAD
    for (uint i = 0; i < len; i++) { /* ... */ }
}

// Use calldata for read-only external function params (saves copy)
function process(uint[] calldata data) external pure returns (uint) {
    return data.length;
}
```

## 2. Pack Storage Variables (save slots)
```solidity
// Bad: 3 slots (each takes a full 32 bytes)
uint128 a; uint256 b; uint128 c;

// Good: 2 slots — a and c pack into 1 slot
uint128 a; uint128 c; uint256 b;
```

## 3. Use Mappings Instead of Arrays Where Possible
Mappings cost O(1) reads; array lookups can be O(n) if searching.

## 4. Avoid Unnecessary SSTOREs
```solidity
// Each non-zero→non-zero SSTORE costs 5,000 gas
// non-zero→zero (delete) REFUNDS 10,000 gas
// Set to zero when done to claim refund:
delete users[addr]; // better than users[addr] = 0 for structs
```

## 5. Use Custom Errors (cheaper than revert strings)
```solidity
error InsufficientBalance(uint256 have, uint256 need);
revert InsufficientBalance(balance, amount); // saves ~200 gas vs string
```

## 6. Unchecked Arithmetic
```solidity
// Safe to unchecked when you've validated bounds:
for (uint i = 0; i < len;) {
    // ... 
    unchecked { ++i; } // saves ~20 gas per iteration
}
```

## 7. Short-circuit Checks
```solidity
// Put cheap checks first — expensive ones only run if needed
require(amount > 0, "Zero");           // cheap
require(balanceOf(msg.sender) >= amount, "Low balance"); // SLOAD, runs second
```

## 8. Immutables and Constants
```solidity
uint256 public constant FEE = 300;     // compiled into bytecode — free reads
address public immutable OWNER;         // set once in constructor, gas-free reads
```

Following these patterns can reduce deployment and transaction costs by 20–40%.

import { WebSocketServer, WebSocket } from 'ws';
import { createServer } from 'http';
import { createClient } from '@supabase/supabase-js';
import { parse } from 'url';

const supabase = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_SERVICE_KEY!);

interface Client {
  ws: WebSocket;
  userId: string;
  rooms: Set<string>;
}

const clients = new Map<string, Client>();
const rooms = new Map<string, Set<string>>(); // roomId → Set<userId>

const server = createServer();
const wss = new WebSocketServer({ server });

function broadcast(roomId: string, message: object, excludeUserId?: string) {
  const room = rooms.get(roomId);
  if (!room) return;
  const payload = JSON.stringify(message);
  for (const uid of room) {
    if (uid === excludeUserId) continue;
    clients.get(uid)?.ws.send(payload);
  }
}

function joinRoom(userId: string, roomId: string) {
  if (!rooms.has(roomId)) rooms.set(roomId, new Set());
  rooms.get(roomId)!.add(userId);
  clients.get(userId)?.rooms.add(roomId);
}

function leaveRoom(userId: string, roomId: string) {
  rooms.get(roomId)?.delete(userId);
  clients.get(userId)?.rooms.delete(roomId);
  if (rooms.get(roomId)?.size === 0) rooms.delete(roomId);
}

wss.on('connection', async (ws, req) => {
  // Authenticate via token in query
  const { query } = parse(req.url ?? '', true);
  const token = query.token as string;
  if (!token) { ws.close(4001, 'Unauthorized'); return; }

  const { data: { user } } = await supabase.auth.getUser(token);
  if (!user) { ws.close(4001, 'Invalid token'); return; }

  const userId = user.id;
  clients.set(userId, { ws, userId, rooms: new Set() });
  ws.send(JSON.stringify({ type: 'connected', userId }));

  ws.on('message', (data) => {
    try {
      const msg = JSON.parse(data.toString());
      switch (msg.type) {
        case 'join':
          joinRoom(userId, msg.roomId);
          broadcast(msg.roomId, { type: 'user_joined', userId, roomId: msg.roomId }, userId);
          break;
        case 'leave':
          leaveRoom(userId, msg.roomId);
          broadcast(msg.roomId, { type: 'user_left', userId, roomId: msg.roomId });
          break;
        case 'message':
          broadcast(msg.roomId, { type: 'message', userId, roomId: msg.roomId, content: msg.content, ts: Date.now() }, userId);
          break;
      }
    } catch { /* ignore malformed */ }
  });

  ws.on('close', () => {
    const client = clients.get(userId);
    if (client) { client.rooms.forEach(r => leaveRoom(userId, r)); }
    clients.delete(userId);
  });

  ws.on('error', (err) => { console.error(`WS error for ${userId}:`, err.message); });
});

server.listen(3002, () => console.log('WebSocket server on :3002'));

