const bytecode = '0x...' as `0x${string}`;

async function deployContract() {
  console.log('Deploying to Arc Testnet...');

  // Estimate gas
  const deployTx = await publicClient.estimateContractGas({
    account: account.address,
    abi, bytecode,
    args: ['MyToken', 'MTK', 1_000_000n * 10n**18n, account.address],
  });
